-- BRK-160 — form_template_library catalog + 5 seeded templates
--
-- The wizard's Custom Forms module lets users pick from a fixed set of
-- pre-built form templates. Selected templates are pushed to Dmytro's
--   POST /onboarding-app/custom-form-template/import-json
-- endpoint at Complete (see lib/clients/fp-api/endpoints/forms.ts).
--
-- This migration creates the catalog table and seeds the 5 templates
-- Dmytro shipped for the 2026-05-26 Permission Setting release. The
-- inlined template_json blobs are a verbatim copy of the .json files in
-- supabase/seed/form-templates/ (kept in the repo for diffability).
--
-- Idempotent: safe to re-run. Schema changes via ALTER TABLE; row upsert
-- on (name) refreshes template_json + description + updated_at.

create table if not exists form_template_library (
  id            uuid primary key default extensions.uuid_generate_v4(),
  name          text not null unique,
  description   text,
  template_json jsonb not null,
  is_active     boolean not null default true,
  created_at    timestamptz not null default now(),
  updated_at    timestamptz not null default now()
);

create index if not exists idx_form_template_library_active
  on form_template_library(is_active);

drop trigger if exists form_template_library_updated_at on form_template_library;
create trigger form_template_library_updated_at
  before update on form_template_library
  for each row execute procedure update_updated_at_column();

-- No RLS: orchestrator reads this catalog server-side via the postgres.js
-- connection (DATABASE_URL), not from the browser. Pattern matches
-- import_files (migration 007).

-- ---------------------------------------------------------------------------
-- Seed: 5 templates from supabase/seed/form-templates/*.json
-- Source: Dmytro Linnyk, BRK-160 comment 226d9504 (2026-05-26).
-- ---------------------------------------------------------------------------

